import { Fragment } from "react"
import { Star, RefreshCw } from 'lucide-react';
import TagChip from '$lib/components/ui/TagChip.js';
import FolderToolbar from '$lib/components/panels/folderPanel/components/FolderToolbar';
import MigrationBar from '$lib/components/panels/folderPanel/components/MigrationBar.js';
import PenetrateSettingsBar from '$lib/components/panels/folderPanel/components/PenetrateSettingsBar.js';
import SelectionBar from '$lib/components/panels/folderPanel/components/SelectionBar.js';
import SearchBar from '$lib/components/ui/SearchBar.js';
import VirtualSearchBar from '$lib/components/ui/VirtualSearchBar.js';
import FavoriteTagPanel from '$lib/components/panels/folderPanel/components/FavoriteTagPanel.js';
import { getFolderContext } from '../context/FolderContext.js';
import {
		folderTabActions,
		isVirtualPath,
		tabShowPenetrateSettingsBar
	} from '$lib/components/panels/folderPanel/stores/folderTabStore';
import { virtualPanelSettingsStore } from '$lib/stores/virtualPanelSettings.js';
import { directoryTreeCache } from '$lib/components/panels/folderPanel/utils/directoryTreeCache';
import { loadVirtualPathData } from '$lib/components/panels/folderPanel/utils/virtualPathLoader';
import { showSuccessToast } from '$lib/utils/toast';
import { createSearchActions } from '../hooks/useSearchActions';
import { createTagActions, type RandomTag } from '../hooks/useTagActions.js';
import { mixedGenderStore, type FavoriteTag } from '$lib/stores/emm/favoriteTagStore.js';
import type { FsItem } from '$lib/types';
interface Props {
		onRefresh: () => void;
		onGoBack: () => void;
		onGoForward: () => void;
		onGoUp: () => void;
		onGoHome: () => void;
		onSetHome: () => void;
		onBatchDelete: () => void;
		/** 是否垂直布局（左右位置时使用） */
		vertical?: boolean;
	}

export function ToolbarCard(props: Props) {
  const {
		onRefresh,
		onGoBack,
		onGoForward,
		onGoUp,
		onGoHome,
		onSetHome,
		onBatchDelete,
		vertical = false
	} = props
  const ctx = getFolderContext();

  const {
      isVirtualInstance,
      panelMode,
      searchKeyword,
      searchSettings,
      deleteStrategy,
      localSearchStore,
      initialPath
    } = ctx;

  const virtualMode = $derived(panelMode === 'folder' ? null : panelMode);

  const searchActions = createSearchActions();

  function setSearchKeyword(kw: string) {
      if (isVirtualInstance) {
        localSearchStore.keyword.set(kw);
      } else {
        folderTabActions.setSearchKeyword(kw);
      }
    }

  const tagActions = createTagActions(() => get(searchKeyword), setSearchKeyword);

  let randomTags = $derived(tagActions.randomTags);

  function handleToggleFolderTree() {
      if (virtualMode === 'history') {
        virtualPanelSettingsStore.toggleHistoryFolderTreeVisible();
      } else if (virtualMode === 'bookmark') {
        virtualPanelSettingsStore.toggleBookmarkFolderTreeVisible();
      } else {
        folderTabActions.toggleFolderTree();
      }
    }

  function handleToggleDeleteStrategy() {
      folderTabActions.toggleDeleteStrategy();
      showSuccessToast('删除策略', get(deleteStrategy) === 'trash' ? '回收站' : '永久');
    }

  function handleToggleInlineTree() {
      if (virtualMode === 'history') {
        virtualPanelSettingsStore.toggleHistoryInlineTreeMode();
      } else if (virtualMode === 'bookmark') {
        virtualPanelSettingsStore.toggleBookmarkInlineTreeMode();
      } else {
        folderTabActions.toggleInlineTreeMode();
      }
    }

  function handleToggleMigrationManager() {
      ctx.showMigrationManager = !ctx.showMigrationManager;
    }

  function handleToggleFavoriteTagPanel() {
      ctx.showFavoriteTagPanel = !ctx.showFavoriteTagPanel;
    }

  function handleCloseFavoriteTagPanel() {
      ctx.showFavoriteTagPanel = false;
    }

  function handleToggleRandomTagBar() {
      ctx.showRandomTagBar = !ctx.showRandomTagBar;
      if (ctx.showRandomTagBar && randomTags.length === 0) {
        tagActions.refreshRandomTags();
      }
    }

  function handleAppendTag(tag: FavoriteTag, modifier: string = '') {
      tagActions.appendTagToSearch(tag, modifier);
    }

  function handleRandomTagClick(tag: FavoriteTag) {
      tagActions.handleRandomTagClick(tag, handleSearch);
    }

  function refreshRandomTags() {
      tagActions.refreshRandomTags();
    }

  function getVirtualItems(): FsItem[] {
      if (!initialPath) return [];
      try {
        return loadVirtualPathData(initialPath);
      } catch (err) {
        console.error('[ToolbarCard] 加载虚拟路径数据失败:', err);
        return [];
      }
    }

  function handleVirtualSearch(results: FsItem[], keyword: string) {
      console.log('[ToolbarCard.handleVirtualSearch]', { keyword, resultCount: results.length });
      localSearchStore.keyword.set(keyword);
      localSearchStore.results.set(results);
      localSearchStore.isSearching.set(false);
    }

  function handleVirtualSearchValueChange(val: string) {
      localSearchStore.keyword.set(val);
    }

  function handleSearch(keyword: string) {
      console.log('[ToolbarCard.handleSearch] 普通路径搜索', { keyword });
      searchActions.handleSearch(keyword);
    }

  function handleSearchSettingsChange(settings: any) {
      searchActions.handleSearchSettingsChange(settings);
    }
  return (
    <Fragment>

{/*  工具栏  */}
<FolderToolbar onRefresh={onRefresh} onToggleFolderTree={handleToggleFolderTree} onGoBack={onGoBack} onGoForward={onGoForward} onGoUp={onGoUp} onGoHome={onGoHome} onSetHome={onSetHome} onToggleDeleteStrategy={handleToggleDeleteStrategy} onToggleInlineTree={handleToggleInlineTree} showRandomTagBar={ctx.showRandomTagBar} onToggleRandomTagBar={handleToggleRandomTagBar} virtualMode={virtualMode} vertical={vertical}></FolderToolbar>

{/*  搜索栏  */}
{ctx.effectiveShowSearchBar ? (<Fragment>
	{isVirtualInstance ? (<Fragment>
		{/*  虚拟路径（历史/书签）：使用简单的前端搜索组件  */}
		<VirtualSearchBar placeholder={panelMode === 'history' ? '搜索历史记录...' : '搜索书签...'} value={$searchKeyword} items={getVirtualItems()} onSearch={handleVirtualSearch} onValueChange={handleVirtualSearchValueChange}></VirtualSearchBar>
	</Fragment>) : (<Fragment>
		{/*  普通文件夹：使用完整的后端搜索组件  */}
		<div className="relative">
			<div className="flex items-center gap-1">
				<div className="flex-1">
					<SearchBar placeholder="搜索文件..." value={$searchKeyword} onSearch={handleSearch} onSearchChange={setSearchKeyword} storageKey="neoview-folder-search-history" searchSettings={{
							includeSubfolders: $searchSettings.includeSubfolders,
							showHistoryOnFocus: $searchSettings.showHistoryOnFocus,
							searchInPath: $searchSettings.searchInPath
						}} onSettingsChange={handleSearchSettingsChange}></SearchBar>
				</div>
				<button className={`hover:bg-accent shrink-0 rounded border p-1.5 ${ctx.showFavoriteTagPanel
						? 'bg-primary/10 border-primary text-primary'
						: 'border-border'}`} onClick={handleToggleFavoriteTagPanel} title="收藏标签">
					<Star className={`h-4 w-4 ${ctx.showFavoriteTagPanel ? 'fill-primary' : ''}`}></Star>
				</button>
			</div>
			<FavoriteTagPanel visible={ctx.showFavoriteTagPanel} onClose={handleCloseFavoriteTagPanel} onAppendTag={handleAppendTag}></FavoriteTagPanel>
		</div>
	</Fragment>)}
</Fragment>) : null}

{/*  迁移栏  */}
{ctx.effectiveShowMigrationBar ? (<Fragment>
	<MigrationBar showManager={ctx.showMigrationManager} onToggleManager={handleToggleMigrationManager}></MigrationBar>
</Fragment>) : null}

{/*  穿透设置栏  */}
{$tabShowPenetrateSettingsBar && !isVirtualInstance ? (<Fragment>
	<PenetrateSettingsBar></PenetrateSettingsBar>
</Fragment>) : null}

{/*  随机标签栏  */}
{ctx.showRandomTagBar ? (<Fragment>
	<div className="bg-muted/30 border-border flex items-center gap-1.5 border-b px-2 py-1.5">
		<span className="text-muted-foreground shrink-0 text-xs">推荐:</span>
		<div className="flex flex-1 flex-wrap items-center gap-1">
			{randomTags.map((tag) => (<Fragment key={tag.id}>
				<TagChip tag={tag.id} category={tag.cat} display={tag.display} color={tag.isCollect ? tag.color : undefined} isCollect={tag.isCollect} onClick={() => handleRandomTagClick(tag)}></TagChip>
			</Fragment>))}
		</div>
		<button className="hover:bg-accent text-muted-foreground rounded p-1" onClick={refreshRandomTags} title="刷新">
			<RefreshCw className="h-3.5 w-3.5"></RefreshCw>
		</button>
	</div>
</Fragment>) : null}

{/*  选择栏  */}
{ctx.effectiveMultiSelectMode ? (<Fragment>
	<SelectionBar onDelete={onBatchDelete}></SelectionBar>
</Fragment>) : null}</Fragment>
  )
}
